sql:
SELECT COUNT(*)
FROM conflict_events
WHERE event_type = 'protest';

SELECT u.user_name, u.email, u.role, u.organization
FROM users u
INNER JOIN visualizations v ON u.user_id = v.user_id;

SELECT date
FROM conflict_events
WHERE event_type = 'protest';

SELECT location_id, COUNT(*) as conflict_events_count
     FROM conflict_events
     GROUP BY location_id;

SELECT event_id
FROM conflict_events
WHERE conflict_scaled > (SELECT AVG(conflict_scaled) FROM conflict_events);

SELECT AVG(scale) AS average_tempest
FROM conflict_events
WHERE scale > 50;

SELECT event_id 
FROM conflict_events 
WHERE conflict_scaled > (SELECT AVG(conflict_scaled) FROM conflict_events);

SELECT event_id, fatalities
FROM conflict_events
WHERE fatalities = (SELECT MAX(fatalities) FROM conflict_events);

SELECT conflict_events.conflict_unscaled, locations.location_name
FROM conflict_events
INNER JOIN locations ON conflict_events.location_id = locations.location_id;

external_knowledge:
- 'stormy episodes' refers to conflict events;
- 'metropolises bustling with life' indicates cities with a population greater than 5,000,000;
- 'dates they bled' refers to the date of the conflict events;
- 'intensity of their fury' signifies the scaled and unscaled number of conflict events;
- 'whether the tales are incomplete' is about the is_partial status;
- 'how deep their wounds run' represents the fatalities;
- 'the map of their suffering' refers to the geographical coordinates (latitude and longitude);
- 'the stories they whisper to the winds' is the description of the events.

sql:
SELECT event_id, date, conflict_unscaled
FROM conflict_events
WHERE strftime('%m', date) = (SELECT strftime('%m', date) FROM conflict_events WHERE event_id = 1);

external_knowledge:
- 'turbulent waters of conflict' refers to the conflict events;
- 'unique sail identifier' refers to `event_id`;
- 'type of waves they churn' refers to `event_type_id`;
- 'captain's badge' refers to `user_id`;
- 'authority over the deck' refers to `permission`;
- 'day they cast off' refers to `source_date`;
- 'depths of each tempest's strength' refers to `conflict_unscaled`;
- 'wave's whisper' is a metaphor for `sin_conflict_unscaled`;
- 'escarpment of monthly turmoil' refers to the percentile ranking by `conflict_monthly`.

- "Significant conflicts" are those with a scaled conflict intensity greater than 50; 
- "Broad geographical areas" refer to the regions where the location is situated;
- The condition of excluding regions related to Africa means the region's name should not include the word 'Africa' in it.

sql:
SELECT event_type_id, COUNT(event_id) AS count_of_events
FROM event_type_conflict_events
GROUP BY event_type_id;

SELECT FLOOR(conflict_scaled) AS Scaled_Conflict_Events
FROM conflict_events
WHERE fatalities > (SELECT AVG(fatalities) FROM conflict_events);

SELECT event_id, event_type_id
FROM event_type_conflict_events
WHERE event_id = 0 AND event_type_id = 0;

SELECT DISTINCT L.location_name
FROM locations L
JOIN conflict_events CE ON L.location_id = CE.location_id;

external_knowledge:
- 'clashes' in the question refers to conflict events;
- 'big city' refers to London;
- 'types of clashes' means the different `event_type` categories like battle, explosion, and protest;
- 'how many instances of each type' refers to the total unscaled conflict events (`total_conflict_unscaled`) grouped by `event_type`.

sql:
SELECT locations.location_name, locations.region
FROM locations
INNER JOIN conflict_events ON locations.location_id = conflict_events.location_id;
